def _parse_alt(p, i):
    branches = []
    node, i = _parse_cat(p, i)
    branches.append(node)
    while i < len(p) and p[i] == '|':
        node, i = _parse_cat(p, i + 1)
        branches.append(node)
    if len(branches) == 1:
        return branches[0], i
    return ('alt', branches), i


def _parse_cat(p, i):
    items = []
    while i < len(p) and p[i] != '|' and p[i] != ')':
        node, i = _parse_quant(p, i)
        items.append(node)
    if len(items) == 1:
        return items[0], i
    return ('cat', items), i


def _parse_quant(p, i):
    node, i = _parse_atom(p, i)
    while i < len(p) and p[i] in '*+?':
        if p[i] == '*':
            node = ('star', node)
        elif p[i] == '+':
            node = ('plus', node)
        else:
            node = ('opt', node)
        i += 1
    return node, i


def _parse_atom(p, i):
    c = p[i]
    if c == '(':
        node, i = _parse_alt(p, i + 1)
        return node, i + 1
    if c == '[':
        return _parse_class(p, i + 1)
    if c == '.':
        return ('any',), i + 1
    return ('lit', c), i + 1


def _parse_class(p, i):
    neg = False
    if p[i] == '^':
        neg = True
        i += 1
    chars = set()
    first = True
    while first or p[i] != ']':
        first = False
        if i + 2 < len(p) and p[i + 1] == '-' and p[i + 2] != ']':
            for o in range(ord(p[i]), ord(p[i + 2]) + 1):
                chars.add(chr(o))
            i += 3
        else:
            chars.add(p[i])
            i += 1
    return ('class', neg, chars), i + 1


def match(pattern, text):
    node = _parse_alt(pattern, 0)[0]
    n = len(text)

    def m(node, i, k):
        t = node[0]
        if t == 'lit':
            return i < n and text[i] == node[1] and k(i + 1)
        if t == 'any':
            return i < n and k(i + 1)
        if t == 'class':
            return i < n and ((text[i] in node[2]) != node[1]) and k(i + 1)
        if t == 'cat':
            def seq(items, j):
                if not items:
                    return k(j)
                return m(items[0], j, lambda j2: seq(items[1:], j2))
            return seq(node[1], i)
        if t == 'alt':
            for branch in node[1]:
                if m(branch, i, k):
                    return True
            return False
        if t == 'star':
            return star(node[1], i, k)
        if t == 'plus':
            return m(node[1], i, lambda j: star(node[1], j, k))
        return m(node[1], i, k) or k(i)

    def star(child, i, k):
        if m(child, i, lambda j: j > i and star(child, j, k)):
            return True
        return k(i)

    return m(node, 0, lambda i: i == n)
